sql_query:
SELECT "Secondary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Hodgkin Lymphoma';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Secondary endpoint" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Hodgkin Lymphoma'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_endpoint_role(source_value, "Secondary endpoint") AS "endpoint_role"
FROM base;
